    @Test(priority = 1, groups = {"smoke", "regression", "login"})
    @Story("Valid Login Flow")
    @Severity(SeverityLevel.BLOCKER)
    @Description("TC-21: Verify that login works with valid credentials")
    public void TC_21_VerifyLoginWithValidCredentials() {
        Step("Navigate to 192.168.10.124:4001", () -> {
            loginPage.navigate();
        });

        Step("Verify login page displays with Email, Password, Login button, and Register link", () -> {
            loginPage.verifyLoginPageLoaded();
        });

        Step("Enter valid username", () -> {
            String username = System.getenv("TEST_USERNAME");
            if (username == null || username.isEmpty()) {
                String[] creds = loginPage.getLoginDataByRole("Admin");
                username = creds[0];
            }
            loginPage.enterUsername(username);
        });

        Step("Enter valid password", () -> {
            String password = System.getenv("TEST_PASSWORD");
            if (password == null || password.isEmpty()) {
                String[] creds = loginPage.getLoginDataByRole("Admin");
                password = creds[1];
            }
            loginPage.enterPassword(password);
        });

        Step("Click login button", () -> {
            loginPage.clickLoginButton();
        });

        Step("Verify user logged in successfully", () -> {
            loginPage.verifyLoginSuccessful();
        });
    }

